    var extenderPassword by remember { mutableStateOf("") }
    var selectedBindNetwork by remember { mutableStateOf<String?>(null) }
    var pendingBindNetwork by remember { mutableStateOf<RelayWifiCandidate?>(null) }
    var relayBindInProgress by remember { mutableStateOf(false) }
    var relayBindScanInProgress by remember { mutableStateOf(false) }
    val releaseNotes = remember { currentReleaseNotes() }
    val releasePrefs = remember { context.getSharedPreferences("xiro_lite_release_notes", android.content.Context.MODE_PRIVATE) }
    val uiPrefs = remember { context.getSharedPreferences(UI_PREFS_NAME, android.content.Context.MODE_PRIVATE) }
    var debugModeEnabled by remember { mutableStateOf(uiPrefs.getBoolean("debug_mode_enabled", false)) }
    var relayBoundCameraHint by remember {
        mutableStateOf(uiPrefs.getString(RELAY_BOUND_CAMERA_HINT_PREF_KEY, "").orEmpty())
    }
    var relayBoundCameraHintAtMs by remember {
        mutableLongStateOf(uiPrefs.getLong(RELAY_BOUND_CAMERA_HINT_AT_MS_PREF_KEY, 0L))
    }
    var relayBindReconnectUntilMs by remember { mutableLongStateOf(0L) }
    var measurementUnit by remember {
        mutableStateOf(MeasurementUnit.fromStored(uiPrefs.getString(MEASUREMENT_UNIT_PREF_KEY, null)))
    }
    var liveVideoPipelineMode by remember {
        mutableStateOf(
            LiveVideoPipelineMode.fromStored(
                uiPrefs.getString(LIVE_VIDEO_PIPELINE_PREF_KEY, null)
            )
        )
    }
    var flightFeedDecoderStrategy by remember {
        mutableStateOf(
            FlightFeedDecoderStrategy.fromStored(
                uiPrefs.getString(FLIGHT_FEED_DECODER_STRATEGY_PREF_KEY, null)
            )
        )
    }
    var selectedLiveHudItems by remember {
        mutableStateOf(
            normalizeHudSelection(
                uiPrefs.getStringSet(LIVE_VIEW_HUD_PREF_KEY, DEFAULT_LIVE_VIEW_HUD_ITEMS)
                    ?.toSet()
                    ?: DEFAULT_LIVE_VIEW_HUD_ITEMS
            )
        )
    }
    var showDebugModeWarningDialog by remember { mutableStateOf(false) }
    var showDisclaimerDialog by remember { mutableStateOf(true) }
    var showReleaseNotesDialog by remember {
        mutableStateOf(
            releasePrefs.getString("last_ack_version", null) != releaseNotes.version
        )
    }

    var showStoragePermissionDialog by remember { mutableStateOf(false) }
    var storagePromptHandledForSession by remember { mutableStateOf(false) }
    var storageSetupComplete by remember { mutableStateOf(false) }
    var storageSetupRefreshToken by remember { mutableIntStateOf(0) }
    var storageSetupStatus by remember { mutableStateOf("") }
    var telemetryNowMs by remember { mutableLongStateOf(System.currentTimeMillis()) }

    val legacyStoragePermissionLauncher = rememberLauncherForActivityResult(
        contract = ActivityResultContracts.RequestMultiplePermissions()
    ) {
        storageSetupRefreshToken += 1
    }
    val storageSettingsLauncher = rememberLauncherForActivityResult(
        contract = ActivityResultContracts.StartActivityForResult()
    ) {
        storageSetupRefreshToken += 1
    }

    val rtspUrl = selectedProfile.primaryRtspUrl(host)
    val runnableCommands = remember(selectedProfile) {
        XiroCommandCatalog.commandsFor(selectedProfile).filter { it.runnable }
    }
    val connectionStatus = remember(networkInfo) {
        when {
            networkInfo.localIp?.startsWith("192.168.2.") == true -> "Connected to XIRO extender"
            networkInfo.localIp?.startsWith("192.168.1.") == true -> "Connected to camera directly"
            else -> "Not connected to XIRO network"
        }
    }
    val relayHost = remember(networkInfo, selectedProfile) {
        selectedProfile.relayCandidates.firstOrNull()
            ?: if (networkInfo.localIp?.startsWith("192.168.2.") == true) "192.168.2.254" else "192.168.2.254"
    }
    val extenderSettingsEnabled = connectionStatus == "Connected to XIRO extender"

    val latestRemotePacket = remotePackets.firstOrNull()
    val betaUiState = BetaInference.buildUiState(
        networkInfo = networkInfo,
        telemetryResults = telemetryResults + cameraStorageResults,
        watch3014Summary = watch3014Summary,
        recentRemotePackets = remotePackets,
        derivedFlightTelemetry = derivedFlightTelemetry,
        remoteBatteryReading = remoteBatteryReading,
        relayProbeResults = relayProbeResults,
        flightLogStatusText = hjLogStatusText,
        measurementUnit = measurementUnit,
        nowMs = telemetryNowMs
    )
    val actualRelayStatus = cleanRelayField(betaUiState.relayState.status)
    val actualCurrentBoundCamera = cleanRelayField(betaUiState.relayState.currentAirWifi)
    val relayBoundHintFresh =
        relayBoundCameraHint.isNotBlank() &&
            relayBoundCameraHintAtMs > 0L &&
            relayBoundCameraHintAtMs + RELAY_BIND_RECONNECT_GRACE_MS >= telemetryNowMs
    val relayReconnectPending =
        relayBoundHintFresh &&
            relayBindReconnectUntilMs >= telemetryNowMs &&
            relayDisplayNeedsFallback(actualRelayStatus)
    fun persistRelayBoundCameraHint(ssid: String) {
        val normalized = ssid.trim()
        if (normalized.isBlank() || relayDisplayNeedsFallback(normalized)) return
        val now = System.currentTimeMillis()
        relayBoundCameraHint = normalized
        relayBoundCameraHintAtMs = now
        uiPrefs.edit()
            .putString(RELAY_BOUND_CAMERA_HINT_PREF_KEY, normalized)
            .putLong(RELAY_BOUND_CAMERA_HINT_AT_MS_PREF_KEY, now)
            .apply()
    }
    val effectiveRelayStatus = when {
        relayReconnectPending -> "Reconnecting after bind"
        else -> actualRelayStatus
    }
    val effectiveCurrentBoundCamera = when {
        !relayDisplayNeedsFallback(actualCurrentBoundCamera) -> actualCurrentBoundCamera
        relayBoundCameraHint.isNotBlank() -> relayBoundCameraHint
        else -> actualCurrentBoundCamera
    }

    LaunchedEffect(extenderSettingsEnabled, actualCurrentBoundCamera) {
        if (extenderSettingsEnabled && !relayDisplayNeedsFallback(actualCurrentBoundCamera)) {
            persistRelayBoundCameraHint(actualCurrentBoundCamera)
            relayBindReconnectUntilMs = 0L
        }
    }

    LaunchedEffect(Unit) {
        while (true) {
            telemetryNowMs = System.currentTimeMillis()
            delay(1_000)
        }
    }

    LaunchedEffect(showDisclaimerDialog, storagePromptHandledForSession, storageSetupRefreshToken) {
        if (showDisclaimerDialog || storageSetupComplete) return@LaunchedEffect
        if (!storagePromptHandledForSession && shouldPromptForSharedStorageAccess(context)) {
            showStoragePermissionDialog = true
            storageSetupStatus = "Storage access is needed before creating the shared XIRO folder tree."
            return@LaunchedEffect
        }

        val folders = withContext(Dispatchers.IO) { localLibraryManager.ensureFolders() }
        localLibraryItems = localLibraryManager.scanLocalItems(cameraLibrary.items)
        pastFlightSummaries = withContext(Dispatchers.IO) {
            HjFlightLogParser.scanFlightSummaries(folders.metadata)
        }
        installedOfflineMaps = offlineMapManager.listInstalledMaps()
        lastPastFlightsRefreshAtMs = System.currentTimeMillis()
        storageSetupComplete = true
        storageSetupStatus = "Using storage root: ${folders.root.absolutePath}"
    }

    LaunchedEffect(networkInfo.localIp, networkInfo.gatewayIp, mainActivityInForeground, liveViewSessionActive) {
        if (!mainActivityInForeground || liveViewSessionActive) return@LaunchedEffect
        val inferredProfile = detectConnectedProfile(networkInfo = networkInfo, host = host)
        if (selectedProfile.id != inferredProfile.id) {
            selectedProfile = inferredProfile
            liveLogs.add("${formatTimestamp(System.currentTimeMillis())}  Connected profile detected: ${inferredProfile.displayName}")
            if (liveLogs.size > 300) liveLogs.removeAt(0)
        }
    }

    fun appendLog(message: String) {
        liveLogs.add("${formatTimestamp(System.currentTimeMillis())}  $message")
        if (liveLogs.size > 300) liveLogs.removeAt(0)
    }

    suspend fun refreshBindMenu(forceRescan: Boolean = true, logMessage: String? = null) {
        relayBindScanInProgress = true
        try {
            relayProbeResults = relayProbe.probeBindMenu(relayHost, forceRescan = forceRescan)
            logMessage?.let(::appendLog)
        } finally {
            relayBindScanInProgress = false
        }
    }

    fun launchDedicatedCameraViewer(
        initialStreamProfile: StreamProfile? = null,
        autoDebugCapture: Boolean = false,
        launchLabel: String = "Standard"
    ) {
        val requestedProfile = initialStreamProfile ?: StreamProfile.AUTO
        val effectivePipelineMode =
            if (debugModeEnabled) liveVideoPipelineMode else LiveVideoPipelineMode.LEGACY_FLIGHT_SOFTWARE
        appendLog(
            "Launching dedicated camera viewer [$launchLabel] " +
                "with ${requestedProfile.label} (${requestedProfile.transportLabel}) " +
                "via ${effectivePipelineMode.title}" +
                if (effectivePipelineMode.usesFlightFeedDecoderStrategy) {
                    " using ${flightFeedDecoderStrategy.title}"
                } else {
                    ""
                }
        )
        scope.launch {
            appendLog("Running camera init before playback")
            cameraInitResults = cameraInitProbe.run(host)
        }
        context.startActivity(Intent(context, CameraViewerActivity::class.java).apply {
            putExtra(CameraViewerActivity.EXTRA_HOST, host)
            putExtra(CameraViewerActivity.EXTRA_PROFILE_ID, selectedProfile.id)
            putExtra(CameraViewerActivity.EXTRA_INITIAL_STREAM_PROFILE, requestedProfile.name)
            putExtra(CameraViewerActivity.EXTRA_AUTO_DEBUG_CAPTURE, autoDebugCapture)
            putExtra(CameraViewerActivity.EXTRA_VIDEO_PIPELINE_MODE, effectivePipelineMode.name)
            putExtra(
                CameraViewerActivity.EXTRA_FLIGHT_FEED_DECODER_STRATEGY,
                flightFeedDecoderStrategy.name
            )
            putStringArrayListExtra(
                CameraViewerActivity.EXTRA_HUD_ITEMS,
                ArrayList(selectedLiveHudItems)
            )
        })
    }

    fun setLiveVideoPipelineMode(mode: LiveVideoPipelineMode) {
        val effectiveMode =
            if (!debugModeEnabled && mode.debugOnly) {
                LiveVideoPipelineMode.LEGACY_FLIGHT_SOFTWARE
            } else {
                mode
            }
        liveVideoPipelineMode = effectiveMode
        uiPrefs.edit().putString(LIVE_VIDEO_PIPELINE_PREF_KEY, effectiveMode.storedValue).apply()
        appendLog("Live video pipeline set to ${effectiveMode.title}")
    }

    fun setFlightFeedDecoderStrategy(strategy: FlightFeedDecoderStrategy) {
        flightFeedDecoderStrategy = strategy
        uiPrefs.edit().putString(FLIGHT_FEED_DECODER_STRATEGY_PREF_KEY, strategy.storedValue).apply()
        appendLog("Flight Feed decoder strategy set to ${strategy.title}")
    }

    fun requestSharedStorageAccess() {
        showStoragePermissionDialog = false
        storagePromptHandledForSession = true
        storageSetupStatus = "Waiting for storage permission..."
        if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.R) {
            val appSettingsIntent = storageSettingsIntent(context)
            runCatching {
                storageSettingsLauncher.launch(appSettingsIntent)
            }.onFailure {
                storageSettingsLauncher.launch(Intent(Settings.ACTION_MANAGE_ALL_FILES_ACCESS_PERMISSION))
            }
        } else {
            legacyStoragePermissionLauncher.launch(
                arrayOf(
                    Manifest.permission.READ_EXTERNAL_STORAGE,
                    Manifest.permission.WRITE_EXTERNAL_STORAGE
                )
            )
        }
    }

    fun continueWithAppStorage() {
        showStoragePermissionDialog = false
        storagePromptHandledForSession = true
        storageSetupRefreshToken += 1
        storageSetupStatus = "Continuing with app-private storage for this session."
    }

    val importOfflineMapLauncher = rememberLauncherForActivityResult(
        contract = ActivityResultContracts.OpenDocument()
    ) { uri ->
        if (uri == null) return@rememberLauncherForActivityResult
        scope.launch {
            offlineMapStatus = "Importing ${uri.lastPathSegment ?: "offline map"}..."
            offlineMapManager.importMap(uri)
                .onSuccess { imported ->
                    installedOfflineMaps = offlineMapManager.listInstalledMaps()
                    offlineMapStatus = "Imported ${imported.fileName}"
                    appendLog("Offline map imported: ${imported.file.absolutePath}")
                }
                .onFailure { error ->
                    offlineMapStatus = "Map import failed: ${error.message}"
                    appendLog(offlineMapStatus)
                }
        }
    }

    fun isOnXiroWifi(): Boolean =
        networkInfo.localIp?.startsWith("192.168.2.") == true ||
            networkInfo.localIp?.startsWith("192.168.1.") == true

    LaunchedEffect(networkInfo.localIp, host, mainActivityInForeground, liveViewSessionActive) {
        if (!mainActivityInForeground || liveViewSessionActive) return@LaunchedEffect
        if (!isOnXiroWifi()) {
            cameraStorageResults = emptyList()
            return@LaunchedEffect
        }

        while (true) {
            cameraStorageResults = telemetryProbe.readCameraStorage(host)
            delay(15_000)
        }
    }

    LaunchedEffect(networkInfo.localIp, relayHost) {
        if (isOnXiroWifi()) {
            RemoteBatteryHub.start(
                context = context.applicationContext,
                host = relayHost,
                onLog = ::appendLog
            )
        } else {
            RemoteBatteryHub.stop(clearReading = true)
        }
    }

    LaunchedEffect(networkInfo.localIp, remoteUdpRunning, remoteUdpUserDisabled, remoteUdpProbeInProgress) {
        when {
            !isOnXiroWifi() && remoteUdpRunning -> {
                LiveFlightTelemetryHub.stop()
                appendLog("Live flight telemetry listener stopped: not on XIRO Wi-Fi")
            }

            isOnXiroWifi() && !remoteUdpUserDisabled && !remoteUdpProbeInProgress && !remoteUdpRunning -> {
                LiveFlightTelemetryHub.start(onLog = ::appendLog)
                appendLog("Live flight telemetry listener started")
            }
        }
    }

    fun startHjLogSession(tag: String): HjLogRecorderState {
        val state = hjLogRecorder.startSession(tag)
        hjLogStatusText = state.statusText
        appendLog("HJ log session started: ${state.activeFile?.absolutePath ?: state.statusText}")
        return state
    }

    fun stopHjLogSession(): HjLogRecorderState {
        val state = hjLogRecorder.stopSession()
        hjLogStatusText = state.statusText
        state.lastSavedFile?.let {
            appendLog("HJ log saved: ${it.absolutePath}")
        }
        return state
    }

    fun handleAutomaticStreamRecovery(reason: String) {
        val now = System.currentTimeMillis()
        if (now - lastAutoStreamReloadAtMs < 15_000L) return
        lastAutoStreamReloadAtMs = now
        scope.launch {
            val messageToken = ++autoRecoveryMessageToken
            val message = if (reason.contains("preemptive", ignoreCase = true)) {
                "Refreshing live feed before the camera RTSP session expires..."
            } else {
                "Live feed stalled. Reloading stream..."
            }
            captureRecoveryMessage = null
            appendLog("RTSP session watcher: $reason")
            playerReloadToken += 1
            delay(2_000)
            if (autoRecoveryMessageToken != messageToken) return@launch
            captureRecoveryMessage = message
            delay(1_500)
            if (captureRecoveryMessage == message && autoRecoveryMessageToken == messageToken) {
                captureRecoveryMessage = null
            }
        }
    }

    fun resolvedCommandUrl(command: XiroCommand): String =
        when (command.kind) {
            XiroCommandKind.UDP_6800_PROBE -> command.path
            XiroCommandKind.HTTP -> when {
                command.path.startsWith("http://") || command.path.startsWith("https://") -> command.path
                command.path.startsWith("/") -> "http://$host${command.path}"
                else -> "http://$host/${command.path}"
            }
        }

    fun setDebugMode(enabled: Boolean) {
        debugModeEnabled = enabled
        uiPrefs.edit().putBoolean("debug_mode_enabled", enabled).apply()
        if (!enabled && settingsPage == SettingsPage.DEBUG) {
            settingsPage = SettingsPage.ROOT
        }
        if (!enabled && liveVideoPipelineMode.debugOnly) {
            liveVideoPipelineMode = LiveVideoPipelineMode.LEGACY_FLIGHT_SOFTWARE
            uiPrefs.edit()
                .putString(
                    LIVE_VIDEO_PIPELINE_PREF_KEY,
                    LiveVideoPipelineMode.LEGACY_FLIGHT_SOFTWARE.storedValue
                )
                .apply()
            appendLog("Live video pipeline reset to ${LiveVideoPipelineMode.LEGACY_FLIGHT_SOFTWARE.title}")
        }
        appendLog("Debug mode ${if (enabled) "enabled" else "disabled"}")
    }

    fun setMeasurementUnit(unit: MeasurementUnit) {
        measurementUnit = unit
        uiPrefs.edit().putString(MEASUREMENT_UNIT_PREF_KEY, unit.storedValue).apply()
        appendLog("Units changed to ${unit.pageTitle}")
    }

    fun setLiveHudSelection(label: String, enabled: Boolean) {
        val updated = normalizeHudSelection(selectedLiveHudItems).toMutableSet().apply {
            if (enabled) add(label) else remove(label)
        }.toSet()
        selectedLiveHudItems = updated
        uiPrefs.edit().putStringSet(LIVE_VIEW_HUD_PREF_KEY, updated).apply()
    }

    suspend fun performLibraryRefresh(reason: String) {
        libraryRefreshing = true
        val state = cameraMediaController.loadLibrary(host)
        try {
            cameraLibrary = state
            if (reason.contains("video", ignoreCase = true)) {
                localLibraryManager.createVideoPreviewPlaceholder("video_${System.currentTimeMillis()}")
            }
            localLibraryItems = localLibraryManager.scanLocalItems(state.items)
            cameraTraceLog.addAll(0, state.rawResponses.reversed())
            while (cameraTraceLog.size > 120) cameraTraceLog.removeAt(cameraTraceLog.lastIndex)
            lastLibraryRefreshAtMs = System.currentTimeMillis()
            appendLog("Library refresh ($reason): ${state.lastRefreshMessage}")
        } finally {
            libraryRefreshing = false
        }
    }

    suspend fun refreshPastFlightSummaries(reason: String) {
        pastFlightsLoading = true
        try {
            val summaries = withContext(Dispatchers.IO) {
                HjFlightLogParser.scanFlightSummaries(localLibraryManager.ensureFolders().metadata)
            }
            pastFlightSummaries = summaries
            lastPastFlightsRefreshAtMs = System.currentTimeMillis()
            if (reason.isNotBlank()) {
                appendLog("Past flights refreshed ($reason): ${summaries.size} HJ file(s)")
            }
        } finally {
            pastFlightsLoading = false
        }
    }

    LaunchedEffect(selectedProfile.id) {
        host = selectedProfile.primaryHost()
        cameraLibrary = CameraLibraryState(emptyList(), emptyList())
        lastCameraAction = null
        isRecording = false
        appendLog("Active profile set: ${selectedProfile.displayName}")
    }

    LaunchedEffect(selectedTab, host, selectedProfile.id) {
        if (selectedTab != BetaTab.LIBRARY) return@LaunchedEffect
        val now = System.currentTimeMillis()
        if (libraryRefreshing) return@LaunchedEffect
        if (now - lastLibraryRefreshAtMs < 2_500L) return@LaunchedEffect
        performLibraryRefresh("library tab opened")
    }

    LaunchedEffect(selectedTab, settingsPage) {
        if (selectedTab != BetaTab.SETTINGS) return@LaunchedEffect
        if (settingsPage != SettingsPage.PAST_FLIGHTS && settingsPage != SettingsPage.ROOT) return@LaunchedEffect
        val now = System.currentTimeMillis()
        if (pastFlightsLoading) return@LaunchedEffect
        val minRefreshGapMs = if (settingsPage == SettingsPage.PAST_FLIGHTS) 2_500L else 10_000L
        if (now - lastPastFlightsRefreshAtMs < minRefreshGapMs) return@LaunchedEffect
        refreshPastFlightSummaries(if (settingsPage == SettingsPage.PAST_FLIGHTS) "past flights opened" else "settings opened")
    }

    LaunchedEffect(selectedTab, settingsPage, extenderSettingsEnabled, relayHost) {
        if (selectedTab == BetaTab.SETTINGS && extenderSettingsEnabled) {
            when (settingsPage) {
                SettingsPage.ROOT -> {
                    appendLog("Settings opened: auto requesting repeater status and bound camera")
                    relayProbeResults = relayProbe.probeSettingsRoot(relayHost)
                }
                SettingsPage.BIND_CAMERA -> {
                    refreshBindMenu(
                        forceRescan = true,
                        logMessage = "Bind extender screen opened: auto requesting repeater Wi-Fi list"
                    )
                }
                else -> Unit
            }
        }
    }

    LaunchedEffect(extenderSettingsEnabled, selectedTab, settingsPage, relayHost, mainActivityInForeground, liveViewSessionActive) {
        if (!mainActivityInForeground || liveViewSessionActive) return@LaunchedEffect
        if (!extenderSettingsEnabled) return@LaunchedEffect

        while (true) {
            val shouldBackgroundProbe =
                selectedTab == BetaTab.SETTINGS &&
                    settingsPage == SettingsPage.ROOT

            if (shouldBackgroundProbe) {
                relayProbeResults = relayProbe.probeSettingsRoot(relayHost)
            }

            delay(8_000)
        }
    }

    LaunchedEffect(selectedTab, relayHost) {
        if (selectedTab != BetaTab.SETTINGS) {
            relayProbe.closeSession()
        }
    }

    LaunchedEffect(settingsPage) {
        if (settingsPage != SettingsPage.BIND_CAMERA) {
            pendingBindNetwork = null
            relayBindInProgress = false
            relayBindScanInProgress = false
        }
    }

    fun recordCameraOperation(op: CameraOperationResult) {
        lastCameraAction = op
        cameraTraceLog.addAll(0, op.entries.reversed())
        while (cameraTraceLog.size > 120) cameraTraceLog.removeAt(cameraTraceLog.lastIndex)
        appendLog("${op.title}: ${op.summary}")
    }

    fun downloadRemoteLibraryItem(
        item: CameraMediaItem,
        successMessagePrefix: String = "Downloaded remote camera file"
    ) {
        scope.launch {
            libraryDownloadProgress = LibraryDownloadProgress(title = item.name)
            localLibraryManager.downloadToHd(item) { bytesRead, totalBytes ->
                libraryDownloadProgress = LibraryDownloadProgress(
                    title = item.name,
                    bytesRead = bytesRead,
                    totalBytes = totalBytes
                )
            }.onSuccess {
                appendLog("$successMessagePrefix: ${it.name}")
                localLibraryItems = localLibraryManager.scanLocalItems(cameraLibrary.items)
            }.onFailure {
                appendLog("Remote download failed: ${it.message}")
            }
            delay(350)
            libraryDownloadProgress = null
        }
    }

    fun deleteLocalLibraryItem(item: LocalLibraryItem) {
        scope.launch {
            localLibraryManager.deleteLocalItem(item).onSuccess {
                appendLog("Deleted local item: ${item.name}")
                localLibraryItems = localLibraryManager.scanLocalItems(cameraLibrary.items)
                if (selectedLibraryPreview?.id == item.id) {
                    selectedLibraryPreview = null
                }
            }.onFailure {
                appendLog("Local delete failed: ${it.message}")
            }
        }
    }

    suspend fun waitForCaptureRecovery(
        phase: String,
        refreshLibraryReason: String? = null,
        reloadPlayerAfterRecovery: Boolean = showPlayer
    ) {
        appendLog("${phase}: waiting for camera host and Wi-Fi recovery")
        val recovery = cameraMediaController.waitForCameraRecovery(host)
        recordCameraOperation(recovery.operation)
        if (recovery.recovered) {
            if (refreshLibraryReason != null) {
                performLibraryRefresh(refreshLibraryReason)
            }
            if (reloadPlayerAfterRecovery && showPlayer) {
                playerReloadToken += 1
                appendLog("RTSP recovery reload after camera host returned")
            }
            captureRecoveryMessage = null
        } else {
            captureRecoveryMessage = "Camera Wi-Fi is still recovering. Reconnect to the camera when its network returns."
            appendLog("${phase}: recovery timed out before the camera host answered again")
        }
    }

    suspend fun showTransientCaptureMessage(message: String, durationMs: Long = 1500) {
        captureRecoveryMessage = message
        delay(durationMs)
        if (captureRecoveryMessage == message) {
            captureRecoveryMessage = null
        }
    }

    suspend fun runHttpCommandExperiment(command: XiroCommand) {
        val startedAt = System.currentTimeMillis()
        val initialLogIndex = liveLogs.size
        commandExportStatus = "Running ${command.name} and collecting a 20 second log..."
        appendLog("Command test started: ${command.name} (${command.path})")

        val operation = cameraMediaController.runCatalogCommand(host, command)
        recordCameraOperation(operation)

        val recovery = cameraMediaController.waitForCameraRecovery(
            host = host,
            maxWaitMs = 20_000,
            pollIntervalMs = 2_000
        )
        recordCameraOperation(recovery.operation)

        val remainingMs = (20_000 - (System.currentTimeMillis() - startedAt)).coerceAtLeast(0)
        if (remainingMs > 0) {
            appendLog("Command test watch window: keeping the log open for ${remainingMs / 1000}s more")
            delay(remainingMs)
        }

        val logSnapshot = liveLogs.drop(initialLogIndex).toList()
        val report = buildCommandExperimentExportText(
            command = command,
            resolvedUrl = resolvedCommandUrl(command),
            host = host,
            networkInfo = networkInfo,
            profile = selectedProfile,
            commandOperation = operation,
            recoveryOperation = recovery.operation,
            commandLogs = logSnapshot,
            startedAt = startedAt,
            finishedAt = System.currentTimeMillis()
        )
        exportHelper.exportProbeResults(report)
            .onSuccess { file ->
                commandExportStatus = "Saved command log to: ${file.absolutePath}"
                exportStatus = commandExportStatus
                appendLog("Command test export saved: ${file.absolutePath}")
                Toast.makeText(context, commandExportStatus, Toast.LENGTH_LONG).show()
            }
            .onFailure { error ->
                commandExportStatus = "Command export failed: ${error.message}"
                exportStatus = commandExportStatus
                appendLog(commandExportStatus)
                Toast.makeText(context, commandExportStatus, Toast.LENGTH_LONG).show()
            }
    }

    suspend fun runUdpProbeExperiment(command: XiroCommand) {
        val startedAt = System.currentTimeMillis()
        val initialLogIndex = liveLogs.size
        val capturedPackets = mutableListOf<RemoteTelemetryPacket>()
        var hjState: HjLogRecorderState? = null

        commandExportStatus = "Listening on UDP 6800 and collecting a 20 second log..."
        appendLog("UDP probe started: ${command.name} (${command.path})")
        remoteUdpProbeInProgress = true

        if (remoteUdpRunning) {
            LiveFlightTelemetryHub.stop()
            delay(300)
            appendLog("Paused the live UDP monitor so the one-shot probe can bind port 6800")
        }

        startHjLogSession(command.name)

        try {
            withTimeoutOrNull(20_000) {
                remoteTelemetryProbe.watchUdp6800(
                    listenPort = 6800,
                    previewBytes = 32,
                    sourceFilter = null,
                    onPacket = { packet ->
                        capturedPackets += packet
                        hjLogStatusText = hjLogRecorder.appendPacket(packet).statusText
                        if (capturedPackets.size == 1) {
                            appendLog("UDP probe: first packet from ${packet.sourceIp}:${packet.sourcePort}")
                        }
                    },
                    onLog = ::appendLog
                )
            }
        } finally {
            if (hjLogRecorder.currentState().isActive) {
                hjState = stopHjLogSession()
            }
            remoteUdpProbeInProgress = false
            if (isOnXiroWifi() && !remoteUdpUserDisabled) {
                LiveFlightTelemetryHub.start(onLog = ::appendLog)
            }
        }

        appendLog(
            if (capturedPackets.isEmpty()) {
                "UDP probe complete: no packets captured during the 20 second window"
            } else {
                "UDP probe complete: captured ${capturedPackets.size} packets from ${capturedPackets.map { "${it.sourceIp}:${it.sourcePort}" }.distinct().size} source(s)"
            }
        )

        val logSnapshot = liveLogs.drop(initialLogIndex).toList()
        val report = buildUdpProbeExperimentExportText(
            command = command,
            host = host,
            networkInfo = networkInfo,
            profile = selectedProfile,
            watch3014Summary = watch3014Summary,
            packets = capturedPackets,
            commandLogs = logSnapshot,
            startedAt = startedAt,
            finishedAt = System.currentTimeMillis(),
            hjLogFile = hjState?.lastSavedFile
        )
        exportHelper.exportProbeResults(report)
            .onSuccess { file ->
                val hjSuffix = hjState?.lastSavedFile?.let { "  HJ: ${it.absolutePath}" }.orEmpty()
                commandExportStatus = "Saved UDP probe log to: ${file.absolutePath}$hjSuffix"
                exportStatus = commandExportStatus
                appendLog("UDP probe export saved: ${file.absolutePath}")
                Toast.makeText(context, commandExportStatus, Toast.LENGTH_LONG).show()
            }
            .onFailure { error ->
                commandExportStatus = "UDP probe export failed: ${error.message}"
                exportStatus = commandExportStatus
                appendLog(commandExportStatus)
                Toast.makeText(context, commandExportStatus, Toast.LENGTH_LONG).show()
            }
    }

    fun runCommandExperiment(command: XiroCommand) {
        scope.launch {
            runningCommandPath = command.path
            try {
                when (command.kind) {
                    XiroCommandKind.HTTP -> runHttpCommandExperiment(command)
                    XiroCommandKind.UDP_6800_PROBE -> runUdpProbeExperiment(command)
                }
            } catch (t: Throwable) {
                commandExportStatus = "Command test failed: ${t.message ?: t::class.java.simpleName}"
                exportStatus = commandExportStatus
                appendLog(commandExportStatus)
                Toast.makeText(context, commandExportStatus, Toast.LENGTH_LONG).show()
            } finally {
                runningCommandPath = null
            }
        }
    }

    fun setCaptureMode(mode: CaptureMode) {
        scope.launch {
            captureMode = mode
            isRecording = false
            recordCameraOperation(cameraMediaController.setMode(host, mode))
            if (showPlayer) {
                showTransientCaptureMessage("Mode command sent: ${mode.name.lowercase(Locale.US).replaceFirstChar(Char::titlecase)}")
            }
        }
    }
    fun triggerPrimaryCapture() {
        scope.launch {
            val wasRecording = isRecording
            if (captureMode == CaptureMode.PHOTO) {
                val photoResult = cameraMediaController.capturePhoto(host)
                recordCameraOperation(photoResult.operation)
                captureFeedback.playPhotoShutter()
                appendLog("Photo command sent using the verified single-command path")
                if (showPlayer) {
                    showTransientCaptureMessage("Photo command sent")
                }
            } else {
                val op = cameraMediaController.triggerPrimaryAction(host, captureMode, isRecording)
                recordCameraOperation(op)
                if (!wasRecording) {
                    captureFeedback.playRecordBeep()
                } else {
                    captureFeedback.playRecordStopBeep()
                }
                if (op.success) {
                    isRecording = !isRecording
                }
                appendLog(if (wasRecording) "Stop video sent using the verified single-command path" else "Start video sent using the verified single-command path")
                if (showPlayer) {
                    showTransientCaptureMessage(if (wasRecording) "Stop video command sent" else "Start video command sent")
                }
            }
        }
    }

