@Composable
private fun CameraHomeCard(
    profile: LegacyDroneProfile,
    connectionStatus: String,
    detectedDroneLabel: String,
    onOpenCamera: () -> Unit,
    selectedPipelineMode: LiveVideoPipelineMode,
    onSelectPipelineMode: (LiveVideoPipelineMode) -> Unit,
    selectedDecoderStrategy: FlightFeedDecoderStrategy,
    onSelectDecoderStrategy: (FlightFeedDecoderStrategy) -> Unit,
    debugModeEnabled: Boolean,
    onOpenUdpFirstCamera: (() -> Unit)? = null,
    onOpenTcpFirstCamera: (() -> Unit)? = null
) {
    val usesDroneLinkIcon = connectionStatus == "Connected to XIRO extender" &&
        (profile.id == LegacyCompatibilityCatalog.xplorer.id || profile.id == LegacyCompatibilityCatalog.xplorer4k.id)
    val usesDirectCameraIcon = connectionStatus == "Connected to camera directly"
    val heroIcon = when {
        usesDroneLinkIcon -> Icons.AutoMirrored.Outlined.Send
        usesDirectCameraIcon -> Icons.Outlined.CameraAlt
        else -> Icons.Outlined.CameraAlt
    }
    val heroTint = when {
        usesDroneLinkIcon -> XiroDesignTokens.TextPrimary
        usesDirectCameraIcon -> XiroDesignTokens.AccentBright
        else -> XiroDesignTokens.TextPrimary
    }
    val heroLabel = when {
        usesDroneLinkIcon -> "Open Drone Camera"
        usesDirectCameraIcon -> "Open Camera"
        else -> "Open Camera"
    }
    BoxWithConstraints(
        modifier = Modifier.fillMaxWidth()
    ) {
        val heroPanelHeight = (maxWidth * 1.1f).coerceIn(320.dp, 430.dp)
        val heroSize = (maxWidth * 0.34f).coerceIn(124.dp, 156.dp)
        val innerSize = heroSize * 0.56f
        val iconSize = (heroSize * 0.34f).coerceIn(42.dp, 56.dp)
        val labelSpacing = (heroSize * 0.22f).coerceIn(18.dp, 30.dp)
        Box(
            modifier = Modifier
                .fillMaxWidth()
                .heightIn(min = heroPanelHeight)
        ) {
            Column(
                modifier = Modifier
                    .align(Alignment.Center)
                    .padding(vertical = 20.dp),
                horizontalAlignment = Alignment.CenterHorizontally,
                verticalArrangement = Arrangement.spacedBy(labelSpacing)
            ) {
                XiroPillSurface(
                    modifier = Modifier
                        .size(heroSize)
                        .clickable(onClick = onOpenCamera),
                    shape = CircleShape,
                    containerColor = XiroDesignTokens.SurfaceInset
                ) {
                    Box(modifier = Modifier.fillMaxSize(), contentAlignment = Alignment.Center) {
                        XiroPillSurface(
                            modifier = Modifier.size(innerSize),
                            shape = CircleShape,
                            containerColor = XiroDesignTokens.Accent
                        ) {
                            Box(modifier = Modifier.fillMaxSize(), contentAlignment = Alignment.Center) {
                                Icon(
                                    imageVector = heroIcon,
                                    contentDescription = heroLabel,
                                    modifier = Modifier.size(iconSize),
                                    tint = heroTint
                                )
                            }
                        }
                    }
                }
                Text(
                    text = detectedDroneLabel,
                    color = XiroDesignTokens.TextSecondary,
                    style = MaterialTheme.typography.titleSmall
                )
                if (debugModeEnabled) {
                    Column(
                        modifier = Modifier.widthIn(max = 430.dp),
                        horizontalAlignment = Alignment.CenterHorizontally,
                        verticalArrangement = Arrangement.spacedBy(8.dp)
                    ) {
                        Text(
                            text = "Player Path",
                            color = XiroDesignTokens.TextMuted,
                            style = MaterialTheme.typography.labelMedium
                        )
                        FlowRow(
                            modifier = Modifier.fillMaxWidth(),
                            horizontalArrangement = Arrangement.spacedBy(8.dp, Alignment.CenterHorizontally),
                            verticalArrangement = Arrangement.spacedBy(8.dp),
                            maxItemsInEachRow = 3
                        ) {
                            LiveVideoPipelineMode.entries
                                .filter { mode -> debugModeEnabled || !mode.debugOnly }
                                .forEach { mode ->
                                XiroToggleChip(
                                    selected = selectedPipelineMode == mode,
                                    onClick = { onSelectPipelineMode(mode) }
                                ) {
                                    Text(
                                        text = mode.shortLabel,
                                        color = if (selectedPipelineMode == mode) {
                                            XiroDesignTokens.BackgroundBottom
                                        } else {
                                            XiroDesignTokens.TextPrimary
                                        }
                                    )
                                }
                            }
                        }
                        Text(
                            text = selectedPipelineMode.summary,
                            color = XiroDesignTokens.TextMuted,
                            style = MaterialTheme.typography.bodySmall
                        )
                        if (selectedPipelineMode.usesFlightFeedDecoderStrategy) {
                            Text(
                                text = "Flight Feed Decoder",
                                color = XiroDesignTokens.TextMuted,
                                style = MaterialTheme.typography.labelMedium
                            )
                            FlowRow(
                                modifier = Modifier.fillMaxWidth(),
                                horizontalArrangement = Arrangement.spacedBy(8.dp, Alignment.CenterHorizontally),
                                verticalArrangement = Arrangement.spacedBy(8.dp),
                                maxItemsInEachRow = 2
                            ) {
                                FlightFeedDecoderStrategy.entries.forEach { strategy ->
                                    XiroToggleChip(
                                        selected = selectedDecoderStrategy == strategy,
                                        onClick = { onSelectDecoderStrategy(strategy) }
                                    ) {
                                        Text(
                                            text = strategy.shortLabel,
                                            color = if (selectedDecoderStrategy == strategy) {
                                                XiroDesignTokens.BackgroundBottom
                                            } else {
                                                XiroDesignTokens.TextPrimary
                                            }
                                        )
                                    }
                                }
                            }
                            Text(
                                text = selectedDecoderStrategy.summary,
                                color = XiroDesignTokens.TextMuted,
                                style = MaterialTheme.typography.bodySmall
                            )
                        }
                    }
                }
                if (debugModeEnabled && onOpenUdpFirstCamera != null && onOpenTcpFirstCamera != null) {
                    Column(
                        modifier = Modifier.widthIn(max = 430.dp),
                        horizontalAlignment = Alignment.CenterHorizontally,
                        verticalArrangement = Arrangement.spacedBy(10.dp)
                    ) {
                        Text(
                            text = "Debug live-view launchers start a rooted combo log in XIRO/live_view_logs for the full Live View session.",
                            color = XiroDesignTokens.TextMuted,
                            style = MaterialTheme.typography.bodySmall
                        )
                        Row(
                            modifier = Modifier.fillMaxWidth(),
                            horizontalArrangement = Arrangement.spacedBy(8.dp)
                        ) {
                            XiroSecondaryButton(
                                onClick = onOpenUdpFirstCamera,
                                modifier = Modifier.weight(1f)
                            ) {
                                Text("UDP First + Log")
                            }
                            XiroSecondaryButton(
                                onClick = onOpenTcpFirstCamera,
                                modifier = Modifier.weight(1f)
                            ) {
                                Text("TCP First + Log")
                            }
                        }
                    }
                }
            }
        }
    }
}

private fun cameraHomeDroneLabel(profile: LegacyDroneProfile): String =
    when (profile.id) {
        "xplorer" -> "XPLORER"
        "xplorer_4k" -> "XPLORER 4K"
        "gimbal_handheld" -> "GIMBAL HANDHELD"
        "repeater_tiny_q" -> "TINY-Q RELAY"
        else -> profile.displayName.uppercase(Locale.US)
    }

private suspend fun detectConnectedProfile(
    networkInfo: DroneNetworkInfo,
    host: String
): LegacyDroneProfile {
    val localIp = networkInfo.localIp.orEmpty()
    val gatewayIp = networkInfo.gatewayIp.orEmpty()

    if (localIp.startsWith("192.168.1.") || gatewayIp.startsWith("192.168.1.")) {
        return LegacyCompatibilityCatalog.gimbalHandheld
    }

    if (localIp.startsWith("192.168.2.") || gatewayIp.startsWith("192.168.2.")) {
        val cameraHost = host.trim().takeIf { it.isNotBlank() && !it.startsWith("192.168.2.") }
            ?: LegacyCompatibilityCatalog.xplorer.primaryHost()
        return if (probeAmbarella4k(cameraHost)) {
            LegacyCompatibilityCatalog.xplorer4k
        } else {
            LegacyCompatibilityCatalog.xplorer
        }
    }

    return LegacyCompatibilityCatalog.defaultProfile
}

private suspend fun probeAmbarella4k(host: String): Boolean = withContext(Dispatchers.IO) {
    val urlString = "http://$host/cgi-bin/get_amba_4k_version"
    try {
        val conn = URL(urlString).openConnection() as HttpURLConnection
        conn.requestMethod = "GET"
        conn.connectTimeout = 1500
        conn.readTimeout = 1500
        conn.setRequestProperty("User-Agent", "XIRO-Lite")
        conn.setRequestProperty("Connection", "close")

        val code = conn.responseCode
        val body = try {
            val stream = if (code in 200..299) conn.inputStream else conn.errorStream
            if (stream != null) {
                BufferedReader(InputStreamReader(stream)).use { it.readText() }
            } else {
                ""
            }
        } catch (_: Exception) {
            ""
        }

        code in 200..299 && (
            body.contains("amba", ignoreCase = true) ||
                body.contains("4k", ignoreCase = true) ||
                body.contains("version", ignoreCase = true) ||
                body.isBlank()
            )
    } catch (_: Exception) {
        false
    }
}


@Composable
private fun CameraStepSequenceCard(lastAction: CameraOperationResult?) {
    XiroAppCard {
        Column(Modifier.padding(16.dp), verticalArrangement = Arrangement.spacedBy(10.dp)) {
            Text("Capture Prep Sequence", style = MaterialTheme.typography.titleLarge, color = Color(0xFFF2F4F7))
            Text("Shows each camera step explicitly so you can see where photo/video preparation fails.", color = Color(0xFFD7DCE3))
            if (lastAction == null) {
                Text("No capture sequence logged yet.", color = Color(0xFFD7DCE3))
            } else {
                Text("Action: ${lastAction.title}", color = Color(0xFFF2F4F7))
                lastAction.entries.forEachIndexed { index, entry ->
                    Card(
                        modifier = Modifier.fillMaxWidth(),
                        colors = CardDefaults.cardColors(containerColor = Color(0xFF2D333D))
                    ) {
                        Column(Modifier.padding(10.dp), verticalArrangement = Arrangement.spacedBy(4.dp)) {
                            Text("${index + 1}. ${entry.action}", color = Color(0xFFF2F4F7))
                            Text(entry.status, style = MaterialTheme.typography.bodySmall, color = Color(0xFFD7DCE3))
                            if (entry.url.isNotBlank()) Text(entry.url, style = MaterialTheme.typography.bodySmall, fontFamily = FontFamily.Monospace, color = Color(0xFFD7DCE3))
                            if (entry.body.isNotBlank()) Text(entry.body.take(180), style = MaterialTheme.typography.bodySmall, fontFamily = FontFamily.Monospace, color = Color(0xFFD7DCE3))
                        }
                    }
                }
            }
        }
    }
}


