@Composable
@OptIn(ExperimentalLayoutApi::class)
private fun TelemetryActionRow(
    telemetryRunning: Boolean,
    watch3014Running: Boolean,
    remoteUdpRunning: Boolean,
    onTelemetryOnce: () -> Unit,
    onToggleTelemetry: () -> Unit,
    onWatch3014: () -> Unit,
    onToggleUdp: () -> Unit
) {
    Card(modifier = Modifier.fillMaxWidth()) {
        FlowRow(
            modifier = Modifier.padding(12.dp),
            horizontalArrangement = Arrangement.spacedBy(8.dp),
            verticalArrangement = Arrangement.spacedBy(8.dp)
        ) {
            Button(onClick = onTelemetryOnce) { Text("Telemetry Once") }
            Button(onClick = onToggleTelemetry) { Text(if (telemetryRunning) "Stop Telemetry" else "Start Telemetry") }
            Button(onClick = onWatch3014) { Text(if (watch3014Running) "Stop 3014" else "Watch 3014") }
            Button(onClick = onToggleUdp) { Text(if (remoteUdpRunning) "Pause Live UDP" else "Resume Live UDP") }
        }
    }
}


@Composable
private fun CandidateFieldsCard(fields: List<TelemetryFieldCandidate>) {
    Card(modifier = Modifier.fillMaxWidth()) {
        Column(Modifier.padding(12.dp), verticalArrangement = Arrangement.spacedBy(6.dp)) {
            Text("Candidate Telemetry Fields", style = MaterialTheme.typography.titleMedium)
            if (fields.isEmpty()) {
                Text("No candidate fields yet. Start 3014 watch or UDP 6800 capture.")
            } else {
                fields.forEach { field ->
                    Text("${field.label}: ${field.value}  [${field.confidence}]  ${field.source}")
                }
            }
        }
    }
}

@Composable
private fun UdpMonitorWindowsCard(packet: RemoteTelemetryPacket?) {
    XiroAppCard {
        Column(Modifier.padding(16.dp), verticalArrangement = Arrangement.spacedBy(10.dp)) {
            Text("Live UDP Monitor Windows", style = MaterialTheme.typography.titleLarge, color = Color(0xFFF2F4F7))
            Text(
                "Debug-only live windows for the known UDP leads. Changed values are highlighted so you can watch the packet evolve in real time.",
                color = Color(0xFFD7DCE3),
                style = MaterialTheme.typography.bodySmall
            )
            if (packet == null) {
                Text(
                    "Start UDP 6800 watch to populate these windows.",
                    color = Color(0xFFD7DCE3),
                    style = MaterialTheme.typography.bodyMedium
                )
            } else {
                Text(
                    "Latest packet ${formatTimestamp(packet.timestampMs)}  ${packet.sourceIp}:${packet.sourcePort}  ${packet.stateGuess?.label ?: "Unknown"}",
                    color = Color(0xFF9FE870),
                    style = MaterialTheme.typography.bodySmall
                )
                FlowRow(
                    horizontalArrangement = Arrangement.spacedBy(8.dp),
                    verticalArrangement = Arrangement.spacedBy(8.dp)
                ) {
                    LegacyTelemetryHints.knownOffsetIndexes().forEach { index ->
                        UdpOffsetWindow(packet = packet, index = index)
                    }
                    LegacyTelemetryHints.knownPairStartIndexes().forEach { startIndex ->
                        UdpPairWindow(packet = packet, startIndex = startIndex)
                    }
                }
            }
        }
    }
}

@Composable
private fun UdpOffsetWindow(
    packet: RemoteTelemetryPacket,
    index: Int
) {
    val value = packet.watchedOffsets.firstOrNull { it.index == index }
    val changed = value?.changed == true
    Card(
        modifier = Modifier.width(168.dp),
        shape = RoundedCornerShape(18.dp),
        colors = CardDefaults.cardColors(
            containerColor = if (changed) Color(0xFF33482A) else Color(0xFF2D333D)
        ),
        border = BorderStroke(1.dp, if (changed) Color(0xFF9FE870) else Color(0x22FFFFFF))
    ) {
        Column(Modifier.padding(12.dp), verticalArrangement = Arrangement.spacedBy(6.dp)) {
            Text(
                LegacyTelemetryHints.offsetLabel(index),
                color = Color(0xFFF2F4F7),
                style = MaterialTheme.typography.titleSmall
            )
            Text(
                "UDP[$index]",
                color = Color(0xFFD7DCE3),
                style = MaterialTheme.typography.bodySmall,
                fontFamily = FontFamily.Monospace
            )
            if (value == null) {
                Text("--", color = Color(0xFFF2F4F7), style = MaterialTheme.typography.headlineSmall)
            } else {
                Text(
                    value.unsigned.toString(),
                    color = Color(0xFFF2F4F7),
                    style = MaterialTheme.typography.headlineSmall
                )
                Text(
                    "hex ${value.hex}  signed ${value.signed}",
                    color = Color(0xFFD7DCE3),
                    style = MaterialTheme.typography.bodySmall
                )
                Text(
                    if (changed) "Changed in latest packet" else "Stable in latest packet",
                    color = if (changed) Color(0xFF9FE870) else Color(0xFFB8C0CC),
                    style = MaterialTheme.typography.bodySmall
                )
            }
            LegacyTelemetryHints.offsetHint(index)?.let { hint ->
                Text(
                    hint,
                    color = Color(0xFFD7DCE3),
                    style = MaterialTheme.typography.bodySmall
                )
            }
        }
    }
}

@Composable
private fun UdpPairWindow(
    packet: RemoteTelemetryPacket,
    startIndex: Int
) {
    val value = packet.watchedPairs.firstOrNull { it.startIndex == startIndex }
    val changed = packet.watchedOffsets.any { (it.index == startIndex || it.index == startIndex + 1) && it.changed }
    Card(
        modifier = Modifier.width(168.dp),
        shape = RoundedCornerShape(18.dp),
        colors = CardDefaults.cardColors(
            containerColor = if (changed) Color(0xFF283D49) else Color(0xFF2D333D)
        ),
        border = BorderStroke(1.dp, if (changed) Color(0xFF82D9FF) else Color(0x22FFFFFF))
    ) {
        Column(Modifier.padding(12.dp), verticalArrangement = Arrangement.spacedBy(6.dp)) {
            Text(
                LegacyTelemetryHints.pairLabel(startIndex),
                color = Color(0xFFF2F4F7),
                style = MaterialTheme.typography.titleSmall
            )
            Text(
                "UDP[$startIndex..${startIndex + 1}]",
                color = Color(0xFFD7DCE3),
                style = MaterialTheme.typography.bodySmall,
                fontFamily = FontFamily.Monospace
            )
            if (value == null) {
                Text("--", color = Color(0xFFF2F4F7), style = MaterialTheme.typography.headlineSmall)
            } else {
                Text(
                    value.u16le.toString(),
                    color = Color(0xFFF2F4F7),
                    style = MaterialTheme.typography.headlineSmall
                )
                Text(
                    "s16 ${value.s16le}  hex ${value.hex}",
                    color = Color(0xFFD7DCE3),
                    style = MaterialTheme.typography.bodySmall
                )
                Text(
                    if (changed) "Changed in latest packet" else "Stable in latest packet",
                    color = if (changed) Color(0xFF82D9FF) else Color(0xFFB8C0CC),
                    style = MaterialTheme.typography.bodySmall
                )
            }
            LegacyTelemetryHints.pairHint(startIndex)?.let { hint ->
                Text(
                    hint,
                    color = Color(0xFFD7DCE3),
                    style = MaterialTheme.typography.bodySmall
                )
            }
        }
    }
}


