private fun RelayBindCard(
    relayBindSsid: String,
    relayBindPassword: String,
    onSsidChange: (String) -> Unit,
    onPasswordChange: (String) -> Unit,
    onBind: () -> Unit,
    relayState: RelayStateUi
) {
    Card(modifier = Modifier.fillMaxWidth()) {
        Column(Modifier.padding(12.dp), verticalArrangement = Arrangement.spacedBy(8.dp)) {
            Text("Relay / Range Extender", style = MaterialTheme.typography.titleMedium)
            Text("Best-effort candidate calls inferred from the original XIRO app. Exact relay API paths may still need refinement.")
            Text("Status: ${relayState.status}")
