            if (relayState.availableNetworks.isNotEmpty()) {
                Text("Available Air Wi-Fi Candidates:")
                relayState.availableNetworks.take(5).forEach {
                    Text("${it.ssid}  ch=${it.channel ?: "?"}  signal=${it.signal ?: "?"}")
                }
            }
            OutlinedTextField(value = relayBindSsid, onValueChange = onSsidChange, modifier = Modifier.fillMaxWidth(), label = { Text("Air SSID") })
            OutlinedTextField(value = relayBindPassword, onValueChange = onPasswordChange, modifier = Modifier.fillMaxWidth(), label = { Text("Air Password") })
            Button(onClick = onBind) { Text("Attempt Bind Candidate") }
        }
    }
}


