@Composable
private fun CommandCatalogCard(profile: LegacyDroneProfile) {
    Card(modifier = Modifier.fillMaxWidth()) {
        Column(Modifier.padding(12.dp), verticalArrangement = Arrangement.spacedBy(4.dp)) {
            Text("Command Catalog", style = MaterialTheme.typography.titleMedium)
            Text(profile.displayName, style = MaterialTheme.typography.bodySmall)
            XiroCommandCatalog.commandsFor(profile).forEach {
                Text("${it.name}: ${it.path}")
                if (it.notes.isNotBlank()) {
                    Text(it.notes, style = MaterialTheme.typography.bodySmall, color = Color(0xFFD7DCE3))
                }
            }
        }
    }
}

@Composable
private fun DebugCommandRunnerCard(
    commands: List<XiroCommand>,
    runningCommandPath: String?,
    status: String,
    onRunCommand: (XiroCommand) -> Unit
) {
    XiroAppCard {
        Column(Modifier.padding(16.dp), verticalArrangement = Arrangement.spacedBy(10.dp)) {
            Text("Commands", style = MaterialTheme.typography.titleLarge, color = Color(0xFFF2F4F7))
            Text(
                "Run one debug probe at a time. HTTP commands and the UDP 6800 capture each record a 20 second log window, then auto-export a legacy-model worksheet to XIRO documents storage.",
                color = Color(0xFFD7DCE3)
            )
            if (status.isNotBlank()) {
                Text(status, style = MaterialTheme.typography.bodySmall, color = Color(0xFF9FE870))
            }
            if (commands.isEmpty()) {
                Text("No runnable commands exposed for this profile.", color = Color(0xFFD7DCE3))
            } else {
                commands.forEach { command ->
                    val isRunning = runningCommandPath == command.path
                    Card(
                        modifier = Modifier.fillMaxWidth(),
                        colors = CardDefaults.cardColors(containerColor = Color(0xFF2D333D))
                    ) {
                        Column(Modifier.padding(12.dp), verticalArrangement = Arrangement.spacedBy(8.dp)) {
                            Text(command.name, color = Color(0xFFF2F4F7), style = MaterialTheme.typography.titleMedium)
                            Text(command.path, color = Color(0xFFD7DCE3), style = MaterialTheme.typography.bodySmall, fontFamily = FontFamily.Monospace)
                            if (command.notes.isNotBlank()) {
                                Text(command.notes, color = Color(0xFFD7DCE3), style = MaterialTheme.typography.bodySmall)
                            }
                            Button(
                                onClick = { onRunCommand(command) },
                                enabled = runningCommandPath == null,
                                modifier = Modifier.fillMaxWidth()
                            ) {
                                Text(if (isRunning) "Running..." else "Run + Export 20s Log")
                            }
                        }
                    }
                }
            }
        }
    }
}
